import{j as i,D as o,b as a,c as d,a2 as t,g as n,h as l,f as A,G as E,a3 as p}from"./chunks/framework.BDRKwY9B.js";const P=JSON.parse('{"title":"架构总览","description":"从整体视角理解 Apps、Platform、Kernel 与 Brain 四层架构的职责边界与协同方式。","frontmatter":{"title":"架构总览","description":"从整体视角理解 Apps、Platform、Kernel 与 Brain 四层架构的职责边界与协同方式。","order":1},"headers":[],"relativePath":"architecture/system-overview.md","filePath":"architecture/system-overview.md","lastUpdated":1778839555000}'),B={name:"architecture/system-overview.md"};function c(s,e,h,m,u,b){const r=o("Mermaid");return a(),d("div",null,[e[1]||(e[1]=t('<h1 id="架构总览" tabindex="-1">架构总览 <a class="header-anchor" href="#架构总览" aria-label="Permalink to &quot;架构总览&quot;">​</a></h1><table tabindex="0"><thead><tr><th>层级</th><th>主要职责</th><th>关注点</th></tr></thead><tbody><tr><td><code>apps</code></td><td>感知外部输入、暴露原子命令、维护私有状态</td><td>接平台、接 SDK、做具体动作</td></tr><tr><td><code>platform</code></td><td>发现应用、注册命令、维护事件队列、调度生命周期</td><td>维护应用运行状态和生命周期</td></tr><tr><td><code>kernel</code></td><td>注册节点、组织有向有环图、调度生命周期</td><td>决定下一步做什么</td></tr><tr><td><code>brain</code></td><td>Agent 节点网络、LLM 网关、统一联合记忆</td><td>内建认知能力</td></tr></tbody></table><p><strong>展开说说</strong></p><ul><li><p><code>apps</code> 层是可插拔的感知器与执行器，每个 App 通过 <code>manifest.yaml</code> 声明其自身提供的命令能力，通过 <code>PlatformAPI</code> 与宿主交互。</p></li><li><p><code>platform</code> 层是应用的运行时宿主，它持有<strong>应用层的事件队列</strong>，负责应用发现、命令注册、事件缓存与生命周期管理，并维护与 App 层和 Kernel 层的双向通信。</p></li><li><p><code>kernel</code> 层是内核调度器，它持有<strong>内核层的事件队列</strong>，加载 <code>brain</code> 层的节点，管理节点的生命周期，并维护与 Platform 层和 Brain 层的双向通信。</p></li><li><p><code>brain</code> 层采用基于有向有环图的 Agent / Router 节点网络架构，内建统一 LLM 网关、Embedding 模型网关与统一联合记忆端点，构成智能体的内建认知能力。</p></li></ul><p><strong>挼挼如是说</strong></p><blockquote><p>打个比方：app 是记者（在外面跑、采集信息），platform 是编辑部（安排版面、排期），kernel 是排班经理（决定今天谁干活、先干啥），brain 是主编团队（真正动脑子写稿子）。各层各司其职，谁也不越界。</p></blockquote><h2 id="总体链路" tabindex="-1">总体链路 <a class="header-anchor" href="#总体链路" aria-label="Permalink to &quot;总体链路&quot;">​</a></h2>',7)),(a(),n(p,null,{default:l(()=>[E(r,{id:"mermaid-100",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20subgraph%20OUTER%5B%22%E5%A4%96%E9%83%A8%E4%B8%96%E7%95%8C%22%5D%0A%20%20%20%20%20%20%20%20Adapters%5B%22QQ%20%2F%20%E5%AE%9A%E6%97%B6%E5%99%A8%20%2F%20%E6%96%87%E4%BB%B6%E7%B3%BB%E7%BB%9F%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20APPS%5B%22%E5%BA%94%E7%94%A8%E5%B1%82%20(Apps)%22%5D%0A%20%20%20%20%20%20%20%20APP_QQ%5B%22QQ%20App%22%5D%0A%20%20%20%20%20%20%20%20APP_ALARM%5B%22Alarm%20App%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20PLATFORM%5B%22%E5%B9%B3%E5%8F%B0%E5%B1%82%20(Platform)%22%5D%0A%20%20%20%20%20%20%20%20EVENTS%5B%22%E4%BA%8B%E4%BB%B6%E9%98%9F%E5%88%97%22%5D%0A%20%20%20%20%20%20%20%20CMDS%5B%22%E5%91%BD%E4%BB%A4%E6%B3%A8%E5%86%8C%E8%A1%A8%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20KERNEL%5B%22%E5%86%85%E6%A0%B8%E5%B1%82%20(Kernel)%22%5D%0A%20%20%20%20%20%20%20%20SCHEDULER%5B%22%E5%BF%83%E8%B7%B3%E8%B0%83%E5%BA%A6%E5%99%A8%22%5D%0A%20%20%20%20%20%20%20%20EVENTBUS%5B%22%E4%BA%8B%E4%BB%B6%E6%80%BB%E7%BA%BF%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20BRAIN%5B%22%E8%AE%A4%E7%9F%A5%E5%B1%82%20(Brain%20%2F%20CortexForge)%22%5D%0A%20%20%20%20%20%20%20%20direction%20LR%0A%20%20%20%20%20%20%20%20NODES%5B%22Node%20%2F%20Agent%20%2F%20Router%5Cn(%E6%96%87%E4%BB%B6%E9%A9%B1%E5%8A%A8%E8%AE%A4%E7%9F%A5%E6%8B%93%E6%89%91)%22%5D%0A%20%20%20%20%20%20%20%20GATEWAYS%5B%22LLM%20%2F%20Embedding%20%E7%BD%91%E5%85%B3%22%5D%0A%20%20%20%20%20%20%20%20MEMORY%5B%22%E7%BB%9F%E4%B8%80%E8%81%94%E5%90%88%E8%AE%B0%E5%BF%86%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20OUTER%20--%3E%20APPS%0A%20%20%20%20APPS%20%3C--%3E%7CAppEvent%20%2F%20invoke_command%7C%20PLATFORM%0A%20%20%20%20PLATFORM%20%3C--%3E%7C%E4%BA%8B%E4%BB%B6%20%2F%20%E5%91%BD%E4%BB%A4%7C%20KERNEL%0A%20%20%20%20KERNEL%20%3C--%3E%7C%E8%B0%83%E5%BA%A6%20%2F%20%E7%8A%B6%E6%80%81%7C%20BRAIN%0A"})]),fallback:l(()=>[...e[0]||(e[0]=[A(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<h2 id="四层的职责" tabindex="-1">四层的职责 <a class="header-anchor" href="#四层的职责" aria-label="Permalink to &quot;四层的职责&quot;">​</a></h2><h3 id="app-层-—-感官和手脚" tabindex="-1">App 层 — 感官和手脚 <a class="header-anchor" href="#app-层-—-感官和手脚" aria-label="Permalink to &quot;App 层 — 感官和手脚&quot;">​</a></h3><p>App 是&quot;环境的感知器与执行器&quot;。</p><ul><li>接入外部世界，如 QQ、闹钟、文件系统</li><li>注册命令，供上层在需要时调用</li><li>维护自己的持久化数据</li><li>把外部变化转换为标准化 <code>AppEvent</code></li></ul><h3 id="platform-层-—-身体" tabindex="-1">Platform 层 — 身体 <a class="header-anchor" href="#platform-层-—-身体" aria-label="Permalink to &quot;Platform 层 — 身体&quot;">​</a></h3><p>Platform 是&quot;应用的运行时宿主&quot;。</p><ul><li>发现并实例化应用</li><li>解析 <code>manifest.yaml</code></li><li>注入 <code>PlatformAPI</code></li><li>维护命令注册表与事件队列</li><li>负责与上下层（App &lt;-&gt; Kernel）的双向通信</li><li>负责与维护应用的生命周期</li></ul><h3 id="kernel-层-—-心跳" tabindex="-1">Kernel 层 — 心跳 <a class="header-anchor" href="#kernel-层-—-心跳" aria-label="Permalink to &quot;Kernel 层 — 心跳&quot;">​</a></h3><p>Kernel 是&quot;心跳&quot;。</p><ul><li>编排和组织 Brain 中的节点(Node)</li><li>维护文件事件总线, 分发事件消息</li><li>维护节点的生命周期</li><li>编排命令流，通过 Platform 分发执行</li></ul><h3 id="brain-层-—-大脑" tabindex="-1">Brain 层 — 大脑 <a class="header-anchor" href="#brain-层-—-大脑" aria-label="Permalink to &quot;Brain 层 — 大脑&quot;">​</a></h3><p>Brain 是&quot;内建认知能力层&quot;。</p><ul><li>全部认知状态以文件形式持久化，具备元信息、版本与锁</li><li>Node / Agent / Router 三类节点构成有向二分图（文件 &lt;-&gt; 节点）</li><li>事件总线广播文件变更，节点按 glob 模式订阅并自行激活</li><li>统一 LLM 网关与 Embedding 网关</li><li>统一联合记忆（图式事实记忆 + 情景记忆 + 知识图谱经验记忆）</li><li>双上下文认知：热认知池（人格主上下文）+ 冷认知池（结构化工单）</li><li>未来开放认知节点插件，供第三方扩展认知能力</li></ul><h2 id="设计原则" tabindex="-1">设计原则 <a class="header-anchor" href="#设计原则" aria-label="Permalink to &quot;设计原则&quot;">​</a></h2><ol><li><code>app</code> 只负责感知和执行，不替 brain 做认知</li><li><code>platform</code> 只负责把系统跑起来和双向通信，不替 kernel 做调度决策</li><li><code>kernel</code> 只负责调度与编排，不直接碰 app 的私事，不执行具体认知任务</li><li><code>brain</code> 负责所有 LLM 推理、记忆存取与节点间认知流转</li><li>App 私有数据归 App 自己管</li><li>事件流与命令流保持分离——各走各的道</li></ol><h2 id="下一步阅读" tabindex="-1">下一步阅读 <a class="header-anchor" href="#下一步阅读" aria-label="Permalink to &quot;下一步阅读&quot;">​</a></h2><ul><li>想了解平台与应用之间的契约：读 <a href="./platform-runtime.html">平台运行时</a></li><li>想了解认知的架构：读 <a href="./brain-architecture.html">认知架构</a></li><li>想了解记忆如何设计：读 <a href="./memory-system.html">统一联合记忆</a></li></ul>',17))])}const _=i(B,[["render",c]]);export{P as __pageData,_ as default};
